// 1. OrderUpdatedEvent key: orderId
// Reason: ORDER_PLACED, ORDER_CONFIRMED, ORDER_SHIPPED, ORDER_DELIVERED must arrive
// in order for the same order. orderId key guarantees same partition = ordered delivery.

// 2. TradeEvent key: symbol (e.g., 'TCS')
// Reason: BUY and SELL for same symbol affect position calculation; must be in order.
// Different symbols can be processed in parallel (different partitions).

// 3. UserProfileEvent key: userId
// Reason: Profile field updates for same user must arrive in order
// (e.g., email change, then verification status — order matters).

// 4. PaymentEvent key: paymentId
// Reason: INITIATED → PROCESSING → COMPLETED must arrive in order for same payment.
// Could also use orderId if you want all payment events for an order ordered together.

public class KeyExample {
