// application.properties:
// spring.kafka.producer.transaction-id-prefix=order-service-tx-
// spring.kafka.producer.acks=all
// spring.kafka.producer.enable-idempotence=true

import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.stereotype.Service;

@Service
public class OrderService {
    private final KafkaTemplate<String, OrderPlacedEvent> kafkaTemplate;
    private final OrderRepository orderRepo;

    OrderService(KafkaTemplate<String, OrderPlacedEvent> kt, OrderRepository r) {
        kafkaTemplate = kt; orderRepo = r;
    }

    @Transactional  // DB transaction + Kafka transaction linked
    public Order placeOrder(OrderRequest req) {
        // 1. Save to DB:
        Order order = orderRepo.save(new Order(req));

        // 2. Publish event — in same transaction:
        kafkaTemplate.send("order-placed", order.getId(),
            new OrderPlacedEvent(order.getId(), req.userId(), req.total()));

        // If anything throws here, BOTH DB save AND Kafka publish are rolled back.
        // Consumer never sees the event if the transaction aborts.
        return order;
    }
}

// Note: transactional Kafka requires:
// - transaction-id-prefix configured
// - Spring's KafkaTransactionManager in context
// - @Transactional on the method
// This is the 'exactly-once' pattern for DB + Kafka.

