import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;
import org.springframework.stereotype.Repository;
import org.springframework.data.jpa.repository.JpaRepository;
import jakarta.persistence.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.time.LocalDateTime;

@Entity class FailedEvent {
    @Id @GeneratedValue Long id;
    String topic, key, eventJson, errorMessage;
    boolean retried;
    LocalDateTime failedAt;
    FailedEvent(){}
    FailedEvent(String t, String k, String j, String e){
        topic=t; key=k; eventJson=j; errorMessage=e; retried=false; failedAt=LocalDateTime.now();
    }
}
interface FailedEventRepository extends JpaRepository<FailedEvent, Long> {}

@Service
public class TradeEventPublisher {
    private final KafkaTemplate<String, TradeEvent> kafkaTemplate;
    private final FailedEventRepository failedRepo;
    private final ObjectMapper objectMapper;

    TradeEventPublisher(KafkaTemplate<String, TradeEvent> kt,
                        FailedEventRepository fr, ObjectMapper om) {
        kafkaTemplate = kt; failedRepo = fr; objectMapper = om;
    }

    public void publishTrade(TradeEvent event) {
        kafkaTemplate.send("trade-events", event.symbol(), event)
            .whenComplete((result, ex) -> {
                if (ex != null) {
                    System.err.println("Kafka publish failed for trade: " + event.tradeId());
                    try {
                        // Save to dead-letter DB for replay:
                        failedRepo.save(new FailedEvent(
                            "trade-events",
                            event.symbol(),
                            objectMapper.writeValueAsString(event),
                            ex.getMessage()));
                    } catch (Exception dbEx) {
                        System.err.println("Even dead-letter save failed! " + dbEx.getMessage());
                    }
                } else {
                    System.out.printf("Trade published: %s partition=%d offset=%d%n",
                        event.tradeId(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
                }
            });
    }
}

