import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

@Service
public class DailyReportPublisher {
    private final KafkaTemplate<String, TradeEvent> kafkaTemplate;
    DailyReportPublisher(KafkaTemplate<String, TradeEvent> kt) { kafkaTemplate = kt; }

    public BatchResult publishDailyReports(List<TradeEvent> events) {
        AtomicInteger published = new AtomicInteger(0);
        AtomicInteger failed    = new AtomicInteger(0);

        // Collect futures:
        List<CompletableFuture<SendResult<String, TradeEvent>>> futures = events.stream()
            .map(event -> kafkaTemplate.send("daily-trade-reports", event.userId(), event)
                .whenComplete((result, ex) -> {
                    if (ex != null) { failed.incrementAndGet(); }
                    else            { published.incrementAndGet(); }
                }))
            .toList();

        // Wait for all to complete:
        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();

        return new BatchResult(events.size(), published.get(), failed.get());
    }

    record BatchResult(int total, int published, int failed) {
        @Override public String toString() {
            return String.format("Batch: total=%d published=%d failed=%d", total, published, failed);
        }
    }
}

